struct A {
    int a1, a2, a3;
    A(int v) : a1(v), a2(v), a3(v) {}
};
struct B : public A {
    int b1, b2;
    B(int v) : A(v*v), b1(v), b2(v) {}
};

void DoSomething(A object) {  // Takes A by VALUE
    printf("a1=%d\n", object.a1);
    // b1, b2 are sliced off -- they don't exist in 'object'
}

void main() {
    B b_object(5);
    DoSomething(b_object);  // Object slicing: only a1,a2,a3 copied
}

