// Syntax: return_type operator"" _suffix(parameter_type)

// Example: convert base-3 number string to int
int operator"" _baza_3(const char* str) {
    int result = 0;
    while (*str) {
        result = result * 3 + (*str - '0');
        str++;
    }
    return result;
}

// Example: convert megabytes to bytes
unsigned long long operator"" _Mega(unsigned long long val) {
    return val * 1024 * 1024;
}

void main() {
    int x = 210_baza_3;           // 21 in decimal
    unsigned long long mem = 5_Mega; // 5242880 bytes
}

// Function template
template <class T>
T Sum(T value_1, T value_2) {
    return value_1 + value_2;
}

// Can have default template parameters
template <class T = int>
T Double(T value) {
    return value * 2;
}

void main() {
    int a = Sum(1, 2);           // T = int (deduced)
    float b = Sum(1.5f, 2.3f);   // T = float (deduced)
    int c = Sum<int>(1, 2);      // T = int (explicit)
    int d = Double(5);           // Uses default T = int
}

// Generic class template
template <class T>
class Number {
    T value;
public:
    void Set(T t) { value = t; }
    T Get() { return value; }
};

// Specialization for char -- different behavior
template <>
class Number<char> {
    char value;
public:
    void Set(char t) { value = t - '0'; }  // Convert ASCII to digit
    int Get() { return (int)value; }
};

void main() {
    Number<int> n1;
    n1.Set(42);         // Uses generic template

    Number<char> n2;
    n2.Set('5');        // Uses specialization: value = 5
    int x = n2.Get();  // x = 5
}

