// Restrict templates to specific types using a helper
template <class A, class B>
struct TypeCompare {
    static const bool value = false;
};
template <class A>
struct TypeCompare<A, A> {  // Specialization: same type
    static const bool value = true;
};

template <class T>
class OnlyForInts {
    static_assert(
        TypeCompare<T, int>::value || TypeCompare<T, long>::value,
        "This class only works with int or long!"
    );
    T data;
};

OnlyForInts<int> ok;      // Compiles
